import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { POSTS_COLUMNS } from './constants';
import usePosts from './usePosts';
import Table from '../Table';
import './style.css';

export default function PostsPage() {
  const navigate = useNavigate();
  const { posts, isLoading } = usePosts();
  const firstPostId = posts[0]?.id;

  const tableData = posts.map((post) => ({
    id: post.id,
    title: post.title,
    tag: `User ${post.userId}`,
    body: `${post.body.slice(0, 70)}...`,
    action: (
      <Link
        to={`/posts/${post.id}`}
        className="posts-inline-link"
        onClick={(event) => event.stopPropagation()}
      >
        Read More
      </Link>
    ),
  }));

  return (
    <main className="posts-page">
      <section className="posts-hero">
        <div className="posts-copy">
          <p className="posts-kicker">Posts</p>
          <h1>Read and browse API-powered content.</h1>
          <p>
            This page loads posts from a live API and displays them in a cleaner reusable table.
          </p>
        </div>
        <div className="posts-stats">
          <div className="posts-stat">
            <strong>{isLoading ? '--' : posts.length}</strong>
            <span>Loaded Posts</span>
          </div>
          <div className="posts-stat">
            <strong>API</strong>
            <span>jsonplaceholder</span>
          </div>
        </div>
      </section>

      <section className="posts-router-demo">
        <h2>Router example</h2>
        <p>
          Here you can see the difference between using <code>Link</code>, <code>useNavigate</code>, and
          reading the post id later with <code>useParams</code> inside the details page.
        </p>
        <div className="posts-router-actions">
          <Link
            to={firstPostId ? `/posts/${firstPostId}` : '/posts'}
            className={`posts-demo-button${!firstPostId ? ' disabled' : ''}`}
            onClick={(event) => {
              if (!firstPostId) {
                event.preventDefault();
              }
            }}
          >
            Open first post with Link
          </Link>
          <button
            type="button"
            className="posts-demo-button secondary ui-button ui-button--primary"
            onClick={() => firstPostId && navigate(`/posts/${firstPostId}`)}
            disabled={!firstPostId}
          >
            Open first post with useNavigate
          </button>
        </div>
      </section>

      <Table
        columns={POSTS_COLUMNS}
        data={tableData}
        isLoading={isLoading}
        onRowClick={(row) => navigate(`/posts/${row.id}`)}
      />
    </main>
  );
}
